    }

    .country-selector select {
      margin-left: 8px;
      padding: 6px 12px;
      border-radius: 6px;
      font-size: 14px;
      border: none;
    }

    .price-container {
      position: relative;
      background: linear-gradient(135deg, #6c5ce7 0%, #a29bfe 50%, #fd79a8 100%);
