      <select id="country-select">
        <option value="">Auto-detectar</option>
        <option value="US">United States</option>
        <option value="MX">Mexico</option>
        <option value="BR">Brazil</option>
        <option value="PE">Peru</option>
        <option value="CL">Chile</option>
        <option value="ES">Spain</option>
        <option value="EC">Ecuador</option>
        <option value="PR">Puerto Rico</option>
        <option value="SV">El Salvador</option>
        <option value="CO">Colombia</option>
        <option value="AR">Argentina</option>
        <option value="GT">Guatemala</option>
        <option value="UY">Uruguay</option>
        <option value="PA">Panama</option>
        <option value="HN">Honduras</option>
        <option value="CR">Costa Rica</option>
        <option value="PT">Portugal</option>
        <option value="SE">Sweden</option>
        <option value="CH">Switzerland</option>
        <option value="GB">United Kingdom</option>
      </select>
    </div>

    <div class="price-container">
      <div class="discount-badge">🔥 ¡OFERTA EXCLUSIVA! 🔥</div>
      <h2 class="title">¡PRECIO ESPECIAL PARA TU PAÍS!</h2>
      <div id="price-display" class="loading">💜 Calculando tu precio...</div>
      <a id="buy-button" href="https://sellpay.thrivecart.com/tv-showplan2/" target="_blank" class="cta-button">
        Comprar Ahora
      </a>
    </div>
  </div>

  <script>
    const PRECIO_BASE_USD = 15;
    const MARKUP = 1.67;
    const monedas = {
      US:{codigo:'USD',tasa:1,   nombre:'Estados Unidos', locale:'en-US', bandera:'🇺🇸'},
      MX:{codigo:'MXN',tasa:17.2, nombre:'México',         locale:'es-MX', bandera:'🇲🇽'},
      BR:{codigo:'BRL',tasa:5.2,  nombre:'Brasil',          locale:'pt-BR', bandera:'🇧🇷'},
      PE:{codigo:'PEN',tasa:3.75, nombre:'Perú',            locale:'es-PE', bandera:'🇵🇪'},
      CL:{codigo:'CLP',tasa:950,  nombre:'Chile',           locale:'es-CL', bandera:'🇨🇱'},
      ES:{codigo:'EUR',tasa:0.92, nombre:'España',          locale:'es-ES', bandera:'🇪🇸'},
      EC:{codigo:'USD',tasa:1,    nombre:'Ecuador',         locale:'es-EC', bandera:'🇪🇨'},
      PR:{codigo:'USD',tasa:1,    nombre:'Puerto Rico',     locale:'es-PR', bandera:'🇵🇷'},
      SV:{codigo:'USD',tasa:1,    nombre:'El Salvador',     locale:'es-SV', bandera:'🇸🇻'},
      CO:{codigo:'COP',tasa:4200, nombre:'Colombia',        locale:'es-CO', bandera:'🇨🇴'},
      AR:{codigo:'ARS',tasa:365,  nombre:'Argentina',       locale:'es-AR', bandera:'🇦🇷'},
      GT:{codigo:'GTQ',tasa:7.7,  nombre:'Guatemala',       locale:'es-GT', bandera:'🇬🇹'},
      UY:{codigo:'UYU',tasa:38,   nombre:'Uruguay',         locale:'es-UY', bandera:'🇺🇾'},
      PA:{codigo:'USD',tasa:1,    nombre:'Panama',          locale:'es-PA', bandera:'🇵🇦'},
      HN:{codigo:'HNL',tasa:24,   nombre:'Honduras',        locale:'es-HN', bandera:'🇭🇳'},
      CR:{codigo:'CRC',tasa:560,  nombre:'Costa Rica',      locale:'es-CR', bandera:'🇨🇷'},
      PT:{codigo:'EUR',tasa:0.92, nombre:'Portugal',        locale:'pt-PT', bandera:'🇵🇹'},
      SE:{codigo:'SEK',tasa:10.5, nombre:'Sweden',          locale:'sv-SE', bandera:'🇸🇪'},
      CH:{codigo:'CHF',tasa:0.91, nombre:'Switzerland',     locale:'de-CH', bandera:'🇨🇭'},
      GB:{codigo:'GBP',tasa:0.81, nombre:'United Kingdom',  locale:'en-GB', bandera:'🇬🇧'}
    };

    function formatearPrecio(val, info) {
      return new Intl.NumberFormat(info.locale, {
        style: 'currency',
        currency: info.codigo,
        minimumFractionDigits: /CLP|COP/.test(info.codigo) ? 0 : 2
      }).format(val);
    }

    async function detectarPais() {
      const sel = document.getElementById('country-select').value;
      if (sel && monedas[sel]) return sel;

      const cache = sessionStorage.getItem('countryCode');
      if (cache && monedas[cache]) return cache;

      try {
        const res = await fetch('https://ip-api.com/json/');
        const data = await res.json();
        if (monedas[data.countryCode]) {
          sessionStorage.setItem('countryCode', data.countryCode);
          return data.countryCode;
        }
      } catch {}

      const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
      if (tz.match(/Sao_Paulo|Brasilia/)) return 'BR';
      if (tz.includes('Mexico'))    return 'MX';
      if (tz.includes('Lima'))      return 'PE';
      if (tz.includes('Santiago'))  return 'CL';
      if (tz.includes('Madrid'))    return 'ES';
      if (tz.includes('Guayaquil')) return 'EC';
      if (tz.includes('Salvador'))  return 'SV';
      if (tz.includes('Puerto_Rico'))return 'PR';
      if (tz.match(/New_York|Chicago|Denver|Los_Angeles/)) return 'US';

      const lang = navigator.language.split('-')[1];
      if (monedas[lang]) return lang;
      return 'US';
    }

    async function mostrarPrecio() {
      const disp = document.getElementById('price-display');
      const btn  = document.getElementById('buy-button');
      disp.classList.add('loading');
      btn.style.display = 'none';
      try {
        const pais = await detectarPais();
        const info = monedas[pais];
        const local    = PRECIO_BASE_USD * info.tasa;
        const original = local * MARKUP;
        const ahorro   = Math.round((original - local) / original * 100);

        disp.innerHTML = `
          <div class="original-price">
            <span class="country-flag">${info.bandera}</span>
            Precio normal: ${formatearPrecio(original, info)}
          </div>
          <div class="local-price">${formatearPrecio(local, info)}</div>
          <div class="currency-info">
            <div class="savings">
              🎉 <strong>¡Precio especial para ${info.nombre}!</strong><br>
              💳 Moneda: ${info.codigo}<br>
              💡 <strong>¡Ahorras ${ahorro}% hoy!</strong>
            </div>
          </div>`;
        disp.classList.remove('loading');
        btn.style.display = 'inline-block';
      } catch {
        disp.textContent = '❌ Error ao calcular preço';
      }
    }

    document.getElementById('country-select').addEventListener('change', mostrarPrecio);
    document.addEventListener('DOMContentLoaded', mostrarPrecio);
  </script>
</body>

</html> ]
