};

const PricingWidget: React.FC = () => {
  const [selectedCountry, setSelectedCountry] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(true);

  // Helper to format currency
  const formatPrice = (val: number, info: CurrencyInfo) => {
    return new Intl.NumberFormat(info.locale, {
      style: 'currency',
      currency: info.codigo,
      minimumFractionDigits: /CLP|COP/.test(info.codigo) ? 0 : 2
    }).format(val);
  };

  useEffect(() => {
    const detectCountry = async () => {
      // 1. Check Session Storage
      const cache = sessionStorage.getItem('countryCode');
      if (cache && MONEDAS[cache]) {
        setSelectedCountry(cache);
        setLoading(false);
        return;
      }

      // 2. Try IP-API
      try {
        const res = await fetch('https://ip-api.com/json/');
        const data = await res.json();
        if (data.countryCode && MONEDAS[data.countryCode]) {
          sessionStorage.setItem('countryCode', data.countryCode);
          setSelectedCountry(data.countryCode);
          setLoading(false);
          return;
        }
      } catch (e) {
        // Ignore error, fallthrough to timezone check
      }

      // 3. Fallback to Timezone
      const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
      let detected = 'US';
      if (tz.match(/Sao_Paulo|Brasilia/)) detected = 'BR';
      else if (tz.includes('Mexico')) detected = 'MX';
      else if (tz.includes('Lima')) detected = 'PE';
      else if (tz.includes('Santiago')) detected = 'CL';
      else if (tz.includes('Madrid')) detected = 'ES';
      else if (tz.includes('Guayaquil')) detected = 'EC';
      else if (tz.includes('Salvador')) detected = 'SV';
      else if (tz.includes('Puerto_Rico')) detected = 'PR';
      else if (tz.match(/New_York|Chicago|Denver|Los_Angeles/)) detected = 'US';
      else {
        // 4. Fallback to Browser Language
        const lang = navigator.language.split('-')[1];
        if (lang && MONEDAS[lang]) detected = lang;
      }

      setSelectedCountry(detected);
      setLoading(false);
    };

    detectCountry();
  }, []);

  const currentInfo = MONEDAS[selectedCountry] || MONEDAS['US'];
  const localPrice = PRECIO_BASE_USD * currentInfo.tasa;
  const originalPrice = localPrice * MARKUP;
  const savings = Math.round(((originalPrice - localPrice) / originalPrice) * 100);

  return (
    <div id="pricing" className="py-20 px-4 flex flex-col items-center justify-center min-h-[80vh] bg-gradient-to-b from-[#0f172a] to-[#1e1e2e]">

      {/* Country Selector */}
      <div className="mb-8 text-white text-lg">
        <label className="mr-3 text-gray-300">Selecciona tu país:</label>
        <select 
          value={selectedCountry}
          onChange={(e) => setSelectedCountry(e.target.value)}
          className="bg-[#2d3748] border border-purple-500 rounded px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-purple-400"
        >
          <option value="">Auto-detectar</option>
          {Object.entries(MONEDAS).map(([code, info]) => (
            <option key={code} value={code}>{info.nombre}</option>
          ))}
        </select>
      </div>

      {/* Pricing Card */}
      <div className="relative bg-gradient-to-br from-[#6c5ce7] via-[#a29bfe] to-[#fd79a8] p-8 md:p-12 rounded-3xl text-center w-full max-w-md shadow-2xl border border-white/10 overflow-hidden transform transition-all hover:scale-105 duration-300">

        {/* Floating Money Emoji Background */}
        <div className="absolute -top-4 -right-4 text-9xl opacity-10 animate-float pointer-events-none select-none">
          💰
        </div>

        <div className="inline-block bg-gradient-to-r from-[#38b000] to-[#70e000] text-white px-6 py-2 rounded-full font-bold text-sm md:text-base mb-6 shadow-lg uppercase tracking-wider">
          🔥 ¡OFERTA EXCLUSIVA! 🔥
        </div>

        <h2 className="text-2xl font-black text-white mb-6 drop-shadow-md">
          ¡PRECIO ESPECIAL PARA TU PAÍS!
        </h2>

        {loading ? (
          <div className="text-2xl text-white/80 animate-pulse my-8">
            💜 Calculando tu precio...
          </div>
        ) : (
          <div className="animate-in fade-in zoom-in duration-500">
            <div className="text-red-200 text-lg md:text-xl line-through mb-2 font-medium">
              <span className="mr-2 text-2xl">{currentInfo.bandera}</span>
              Precio normal: {formatPrice(originalPrice, currentInfo)}
            </div>

            <div className="text-5xl md:text-6xl font-black my-6 text-transparent bg-clip-text bg-gradient-to-br from-white to-yellow-300 drop-shadow-sm">
              {formatPrice(localPrice, currentInfo)}
            </div>

            <div className="bg-white/20 backdrop-blur-sm p-4 rounded-xl border border-white/30 text-sm md:text-base text-white font-medium mb-8">
               <p>🎉 ¡Precio especial para <strong>{currentInfo.nombre}</strong>!</p>
               <p className="mt-1">💳 Moneda: {currentInfo.codigo}</p>
               <p className="mt-1 text-yellow-300">💡 ¡Ahorras {savings}% hoy!</p>
            </div>

            <a 
              href="https://sellpay.thrivecart.com/tv-showplan2/"
              target="_blank"
              rel="noopener noreferrer"
              className="block w-full py-4 bg-gradient-to-r from-[#38b000] to-[#70e000] hover:from-[#2d8a00] hover:to-[#5cb800] text-white font-black text-xl rounded-full shadow-[0_4px_20px_rgba(0,0,0,0.3)] hover:shadow-[0_8px_30px_rgba(56,176,0,0.5)] transform hover:-translate-y-1 transition-all duration-300"
            >
              Comprar Ahora
            </a>
          </div>
        )}

        <div className="mt-6 text-white/80 text-sm space-y-1">
          <p>✅ PAGO ÚNICO</p>
          <p>✅ Canales y películas INCLUIDOS</p>
          <p>✅ Pantallas múltiples</p>
        </div>
      </div>

      {/* Brands / Compatibility below pricing */}
      <div className="mt-16 text-center max-w-4xl">
        <h3 className="text-2xl font-bold mb-8 uppercase text-gray-400 tracking-widest">Compatible con las principales marcas</h3>
        <div className="flex flex-wrap justify-center gap-4 text-gray-500 font-bold text-xl">
             <span className="px-4 py-2 border border-gray-700 rounded-lg">SAMSUNG</span>
             <span className="px-4 py-2 border border-gray-700 rounded-lg">LG</span>
             <span className="px-4 py-2 border border-gray-700 rounded-lg">SONY</span>
             <span className="px-4 py-2 border border-gray-700 rounded-lg">PHILIPS</span>
             <span className="px-4 py-2 border border-gray-700 rounded-lg">ROKU</span>
             <span className="px-4 py-2 border border-gray-700 rounded-lg">FIRE TV</span>
             <span className="px-4 py-2 border border-gray-700 rounded-lg">ANDROID TV</span>
             <span className="px-4 py-2 border border-gray-700 rounded-lg">APPLE TV</span>
        </div>
      </div>
    </div>
  );
};

